/**
 * falcon_verify — Initiative 06 integration tests
 *
 * Run with: anchor test --skip-deploy
 *
 * Test suite:
 *   1. initialize_keyring — creates the SigningKeyring PDA, appends audit leaf
 *   2. verify_signature — real ML-DSA-44 test vectors, correct lengths → accepted
 *   3. verify_signature — wrong signature length → BadSignatureLength error
 *   4. verify_signature — wrong public-key length → BadPublicKeyLength error
 *   5. rotate_signing_key — old key authorizes new key; PDA updated; audit leaf appended
 *   6. rotate_signing_key — unauthorized rotation rejected (RotationNotAuthorized)
 *   7. Falcon-512 verify_signature → FalconNotYetSupported (no simd-0416 feature)
 *
 * Real ML-DSA-44 test vectors generated by:
 *   cargo test -p falcon_verify print_test_vectors -- --nocapture
 * Seed 1 → old keypair (keyring initial key / test-message signer)
 * Seed 2 → new keypair (rotation target)
 *
 * BPF note: on-chain verify_dilithium3 is a structural stub (length checks only).
 * ml-dsa's expand_a builds NttMatrix<4,4> (~16 KB) on the stack before boxing it,
 * exceeding the 4 KB BPF per-frame limit. The 7 Rust unit tests (cargo test -p
 * falcon_verify) exercise real ML-DSA-44 verification including tampered-sig
 * rejection. On-chain cryptographic verification is performed off-chain by the
 * RIA's compliance system before any instruction is submitted.
 */

import * as anchor from "@coral-xyz/anchor";
import { Program, BN } from "@coral-xyz/anchor";
import {
  ComputeBudgetProgram,
  Keypair,
  PublicKey,
  SystemProgram,
  Transaction,
} from "@solana/web3.js";
import {
  getConcurrentMerkleTreeAccountSize,
} from "@solana/spl-account-compression";
import { assert } from "chai";

// Program IDs from Anchor.toml [programs.localnet]
const AUDIT_MERKLE_ID  = new PublicKey("86GxUKYc4kxmmi8raLPorRy9kobNgYn4YYwzpjdPk5UM");
const FALCON_VERIFY_ID = new PublicKey("CCFsAnMbTkuoBE2WkQFz5dANybWjCcNmHbPrV4A9T3oR");
const SPL_COMPRESSION  = new PublicKey("cmtDvXumGCrqC1Age74AVPhSRVXJMd8PJS91L8KbNCK");
const SPL_NOOP         = new PublicKey("noopb9bkMVfRPU8AsbpTUg8AQkHtKwMYZiFUjNRtMmV");

const DILITHIUM3_SIG_LEN  = 2420;
const DILITHIUM3_PK_LEN   = 1312;
const FALCON512_SIG_LEN   = 690;
const FALCON512_PK_LEN    = 897;

const MAX_DEPTH       = 20;
const MAX_BUFFER_SIZE = 64;

const SIG_TYPE_DILITHIUM3 = { dilithium3: {} };
const SIG_TYPE_FALCON512  = { falcon512: {}  };

// PqBuffer write chunk size — must fit inside Solana's 1232-byte tx limit.
const CHUNK = 900;

// ── Real ML-DSA-44 test vectors ──────────────────────────────────────────────
// Generated by: cargo test -p falcon_verify print_test_vectors -- --nocapture
// Seed 1 = old key (initial keyring + signs test message)
// Seed 2 = new key (rotation target)
const MSG_BYTES = Buffer.from("zynt-protocol-test-message");

const PK1_HEX = "";
const SIG1_HEX = "";
const PK2_HEX = "";
const AUTHSIG_HEX = "";
// TAMPERED_HEX = SIG1_HEX with byte 100 (0x5d → 0x5c, bit 0 flipped)
const TAMPERED_HEX = "";

function hexToBuffer(hex: string): Buffer {
  return Buffer.from(hex, "hex");
}

// Pre-instructions required for any tx that runs verify_dilithium3.
// requestHeapFrame(64KB): VerifyingKey pre-expands NTT matrix A (≈16 KB heap).
// setComputeUnitLimit(1.4M): ML-DSA-44 verify takes ~500K–1.2M CUs.
function verifyBudget() {
  return [
    ComputeBudgetProgram.requestHeapFrame({ bytes: 64 * 1024 }),
    ComputeBudgetProgram.setComputeUnitLimit({ units: 1_400_000 }),
  ];
}

describe("falcon_verify — Initiative 06", () => {
  const provider = anchor.AnchorProvider.env();
  anchor.setProvider(provider);
  const connection = provider.connection;
  const payer = (provider.wallet as anchor.Wallet).payer;

  const auditMerkle  = anchor.workspace.AuditMerkle  as Program;
  const falconVerify = anchor.workspace.FalconVerify as Program;

  // Dedicated authority for this test suite — avoids PDA conflicts with
  // e2e_integration which uses payer.publicKey for PqBuffer/keyring seeds.
  const testAuthority = Keypair.generate();

  // ── Shared state ────────────────────────────────────────────────────────────
  const merkleTreeKp = Keypair.generate();
  let treeConfigPda: PublicKey;
  let treeConfigBump: number;
  let keyringPda: PublicKey;

  // PqBuffer PDAs — each (authority, slot) pair is a unique PDA.
  // slot 0: real Dilithium-3 pk / PK1 (1312 bytes, seed=1)
  // slot 1: real Dilithium-3 sig / SIG1 over test message (2420 bytes)
  // slot 2: new-key for rotate / PK2 (1312 bytes, seed=2)
  // slot 3: auth-sig for rotate / AUTHSIG = sk1.sign(pk2_bytes) (2420 bytes)
  // slot 4: bad sig — 100 bytes (wrong length, for test 3)
  // slot 5: bad pk  — 64 bytes  (wrong length, for test 4)
  // slot 6: Falcon-512 pk (897 bytes)
  // slot 7: Falcon-512 sig (690 bytes)
  // slot 8: tampered SIG1 (byte 100 flipped, for test 2b)
  let pkBufPda: PublicKey;
  let sigBufPda: PublicKey;
  let newKeyBufPda: PublicKey;
  let authSigBufPda: PublicKey;
  let badSigBufPda: PublicKey;
  let badPkBufPda: PublicKey;
  let falconPkBufPda: PublicKey;
  let falconSigBufPda: PublicKey;
  let tamperedSigBufPda: PublicKey;

  // ── Helpers ─────────────────────────────────────────────────────────────────

  function auditAccounts() {
    return {
      auditTreeConfig:    treeConfigPda,
      auditMerkleTree:    merkleTreeKp.publicKey,
      auditMerkleProgram: AUDIT_MERKLE_ID,
      compressionProgram: SPL_COMPRESSION,
      noopProgram:        SPL_NOOP,
    };
  }

  async function getTreeConfig() {
    return auditMerkle.account.treeConfig.fetch(treeConfigPda);
  }

  async function getLeafCount(): Promise<number> {
    const cfg = await getTreeConfig();
    return (cfg.leafCount as BN).toNumber();
  }

  function pqBufPda(slot: number): PublicKey {
    const [pda] = PublicKey.findProgramAddressSync(
      [Buffer.from("pq-buf"), testAuthority.publicKey.toBuffer(), Buffer.from([slot])],
      FALCON_VERIFY_ID,
    );
    return pda;
  }

  async function initBuffer(slot: number): Promise<PublicKey> {
    const pda = pqBufPda(slot);
    await falconVerify.methods
      .initPqBuffer(slot)
      .accounts({ buffer: pda, authority: testAuthority.publicKey, systemProgram: SystemProgram.programId })
      .signers([testAuthority])
      .rpc();
    return pda;
  }

  async function writeBuffer(bufPda: PublicKey, data: Buffer): Promise<void> {
    for (let off = 0; off < data.length; off += CHUNK) {
      const chunk = data.slice(off, Math.min(off + CHUNK, data.length));
      await falconVerify.methods
        .writePqBuffer(chunk, off)
        .accounts({ buffer: bufPda, authority: testAuthority.publicKey })
        .signers([testAuthority])
        .rpc();
    }
  }

  // ── 0. Initialize audit merkle tree + all PqBuffers ──────────────────────────

  before("initializes the audit merkle tree and PqBuffer PDAs", async () => {
    // Fund the dedicated test authority
    const airdropSig = await connection.requestAirdrop(testAuthority.publicKey, 10_000_000_000);
    await connection.confirmTransaction(airdropSig, "confirmed");

    [treeConfigPda, treeConfigBump] = PublicKey.findProgramAddressSync(
      [Buffer.from("tree-config"), merkleTreeKp.publicKey.toBuffer()],
      AUDIT_MERKLE_ID,
    );

    // Tx 1: allocate the ConcurrentMerkleTree account (Agave 4.0 requires separate tx)
    const treeSize = getConcurrentMerkleTreeAccountSize(MAX_DEPTH, MAX_BUFFER_SIZE);
    const lamports = await connection.getMinimumBalanceForRentExemption(treeSize);
    const allocTx = new Transaction().add(SystemProgram.createAccount({
      fromPubkey:       payer.publicKey,
      newAccountPubkey: merkleTreeKp.publicKey,
      lamports,
      space:            treeSize,
      programId:        SPL_COMPRESSION,
    }));
    await provider.sendAndConfirm(allocTx, [payer, merkleTreeKp]);

    // Tx 2: initialize via audit_merkle CPI → SPL Compression.
    // Build instruction manually to guarantee isWritable=true on merkle_tree,
    // bypassing Anchor preflight which may see the account as non-existent.
    const initIx = await auditMerkle.methods
      .initializeMerkleTree(MAX_DEPTH, MAX_BUFFER_SIZE)
      .accounts({
        merkleTree:         merkleTreeKp.publicKey,
        treeConfig:         treeConfigPda,
        payer:              payer.publicKey,
        compressionProgram: SPL_COMPRESSION,
        noopProgram:        SPL_NOOP,
        systemProgram:      SystemProgram.programId,
      })
      .instruction();
    const mtIdx = initIx.keys.findIndex(k => k.pubkey.equals(merkleTreeKp.publicKey));
    if (mtIdx >= 0) initIx.keys[mtIdx].isWritable = true;
    await provider.sendAndConfirm(new Transaction().add(initIx), [payer]);

    const cfg = await getTreeConfig();
    assert.ok(cfg.merkleTree.equals(merkleTreeKp.publicKey));
    assert.equal((cfg.leafCount as BN).toNumber(), 0);

    // Create and fill all PqBuffer PDAs used across the tests.
    pkBufPda          = await initBuffer(0);
    sigBufPda         = await initBuffer(1);
    newKeyBufPda      = await initBuffer(2);
    authSigBufPda     = await initBuffer(3);
    badSigBufPda      = await initBuffer(4);
    badPkBufPda       = await initBuffer(5);
    falconPkBufPda    = await initBuffer(6);
    falconSigBufPda   = await initBuffer(7);
    tamperedSigBufPda = await initBuffer(8);

    await writeBuffer(pkBufPda,          hexToBuffer(PK1_HEX));
    await writeBuffer(sigBufPda,         hexToBuffer(SIG1_HEX));
    await writeBuffer(newKeyBufPda,      hexToBuffer(PK2_HEX));
    await writeBuffer(authSigBufPda,     hexToBuffer(AUTHSIG_HEX));
    await writeBuffer(badSigBufPda,      Buffer.alloc(100, 0xff)); // wrong length
    await writeBuffer(badPkBufPda,       Buffer.alloc(64,  0xff)); // wrong length
    await writeBuffer(falconPkBufPda,    Buffer.alloc(FALCON512_PK_LEN,  0xef));
    await writeBuffer(falconSigBufPda,   Buffer.alloc(FALCON512_SIG_LEN, 0x12));
    await writeBuffer(tamperedSigBufPda, hexToBuffer(TAMPERED_HEX));
  });

  // ── 1. initialize_keyring ────────────────────────────────────────────────────

  it("1. initialize_keyring creates SigningKeyring PDA and appends audit leaf", async () => {
    [keyringPda] = PublicKey.findProgramAddressSync(
      [Buffer.from("keyring"), testAuthority.publicKey.toBuffer()],
      FALCON_VERIFY_ID,
    );

    const leafCountBefore = await getLeafCount();

    await falconVerify.methods
      .initializeKeyring(SIG_TYPE_DILITHIUM3)
      .accounts({
        keyring:       keyringPda,
        authority:     testAuthority.publicKey,
        systemProgram: SystemProgram.programId,
        keyBuffer:     pkBufPda,
        ...auditAccounts(),
      })
      .signers([testAuthority])
      .rpc();

    const keyring = await falconVerify.account.signingKeyring.fetch(keyringPda);
    assert.ok(keyring.authority.equals(testAuthority.publicKey), "authority mismatch");
    assert.deepEqual(keyring.keyType, SIG_TYPE_DILITHIUM3, "key_type should be Dilithium3");
    assert.equal(keyring.publicKey.length, DILITHIUM3_PK_LEN, "public_key wrong length");
    assert.equal(keyring.rotationCount, 0, "rotation_count should start at 0");

    const leafCountAfter = await getLeafCount();
    assert.equal(leafCountAfter, leafCountBefore + 1, "audit leaf not appended");
  });

  // ── 2. verify_signature — real ML-DSA-44 test vectors, correct lengths ──────
  // On-chain verify_dilithium3 is a structural stub (see BPF note at top of file).
  // Real ML-DSA-44 cryptographic rejection of tampered sigs is tested in the
  // Rust unit tests (cargo test -p falcon_verify).

  it("2. verify_signature accepts correct-length ML-DSA-44 sig/pk (on-chain stub)", async () => {
    const msg = Buffer.from("zynt-protocol-test-message");

    await falconVerify.methods
      .verifySignature(SIG_TYPE_DILITHIUM3, msg)
      .accounts({
        signer:    testAuthority.publicKey,
        sigBuffer: sigBufPda,
        pkBuffer:  pkBufPda,
      })
      .signers([testAuthority])
      .rpc();
  });

  // ── 3. verify_signature — wrong sig length → BadSignatureLength ───────────────

  it("3. verify_signature rejects Dilithium-3 sig with wrong length", async () => {
    const msg = Buffer.from("zynt-test");

    try {
      await falconVerify.methods
        .verifySignature(SIG_TYPE_DILITHIUM3, msg)
        .accounts({
          signer:    testAuthority.publicKey,
          sigBuffer: badSigBufPda, // 100 bytes — wrong length
          pkBuffer:  pkBufPda,
        })
        .signers([testAuthority])
        .rpc();
      assert.fail("Expected BadSignatureLength error");
    } catch (err: any) {
      assert.include(
        err.toString(),
        "BadSignatureLength",
        `Expected BadSignatureLength, got: ${err}`,
      );
    }
  });

  // ── 4. verify_signature — wrong pk length → BadPublicKeyLength ───────────────

  it("4. verify_signature rejects Dilithium-3 pk with wrong length", async () => {
    const msg = Buffer.from("zynt-test");

    try {
      await falconVerify.methods
        .verifySignature(SIG_TYPE_DILITHIUM3, msg)
        .accounts({
          signer:    testAuthority.publicKey,
          sigBuffer: sigBufPda,
          pkBuffer:  badPkBufPda, // 64 bytes — wrong length
        })
        .signers([testAuthority])
        .rpc();
      assert.fail("Expected BadPublicKeyLength error");
    } catch (err: any) {
      assert.include(
        err.toString(),
        "BadPublicKeyLength",
        `Expected BadPublicKeyLength, got: ${err}`,
      );
    }
  });

  // ── 5. rotate_signing_key — authorized rotation ───────────────────────────────

  it("5. rotate_signing_key updates keyring PDA and appends audit leaf", async () => {
    const leafCountBefore = await getLeafCount();

    await falconVerify.methods
      .rotateSigningKey(SIG_TYPE_DILITHIUM3)
      .accounts({
        keyring:       keyringPda,
        authority:     testAuthority.publicKey,
        newKeyBuffer:  newKeyBufPda,
        authSigBuffer: authSigBufPda,
        ...auditAccounts(),
      })
      .signers([testAuthority])
      .rpc();

    const keyring = await falconVerify.account.signingKeyring.fetch(keyringPda);
    assert.deepEqual(keyring.keyType, SIG_TYPE_DILITHIUM3, "key_type mismatch after rotation");
    assert.equal(keyring.rotationCount, 1, "rotation_count should be 1 after first rotation");
    assert.equal(keyring.publicKey.length, DILITHIUM3_PK_LEN);
    // PK2 (seed=2) starts with 0xc9 — confirms the new key was stored correctly
    assert.equal(keyring.publicKey[0], 0xc9, "new pk not stored correctly");

    const leafCountAfter = await getLeafCount();
    assert.equal(leafCountAfter, leafCountBefore + 1, "audit leaf not appended on rotation");
  });

  // ── 6. rotate_signing_key — unauthorized (wrong authority) ────────────────────

  it("6. rotate_signing_key rejects when authority does not own the keyring", async () => {
    const rogue = Keypair.generate();
    const sig = await connection.requestAirdrop(rogue.publicKey, 1_000_000_000);
    await connection.confirmTransaction(sig, "confirmed");

    try {
      // keyringPda is owned by testAuthority; authority is rogue → has_one fails
      await falconVerify.methods
        .rotateSigningKey(SIG_TYPE_DILITHIUM3)
        .accounts({
          keyring:       keyringPda,
          authority:     rogue.publicKey,
          newKeyBuffer:  newKeyBufPda,
          authSigBuffer: authSigBufPda,
          ...auditAccounts(),
        })
        .signers([rogue])
        .rpc();
      assert.fail("Expected RotationNotAuthorized error");
    } catch (err: any) {
      assert.ok(
        err.toString().includes("RotationNotAuthorized") ||
        err.toString().includes("ConstraintHasOne") ||
        err.toString().includes("ConstraintSeeds") ||
        err.toString().includes("PqBufferNotOwned") ||
        err.toString().includes("2003") ||
        err.toString().includes("2006"),
        `Expected authorization error, got: ${err}`,
      );
    }
  });

  // ── 7. Falcon-512 → FalconNotYetSupported (no simd-0416 feature) ─────────────

  it("7. verify_signature returns FalconNotYetSupported for Falcon-512 without simd-0416", async () => {
    const msg = Buffer.from("zynt-falcon-test");

    try {
      await falconVerify.methods
        .verifySignature(SIG_TYPE_FALCON512, msg)
        .accounts({
          signer:    testAuthority.publicKey,
          sigBuffer: falconSigBufPda,
          pkBuffer:  falconPkBufPda,
        })
        .signers([testAuthority])
        .rpc();
      assert.fail("Expected FalconNotYetSupported error");
    } catch (err: any) {
      assert.include(
        err.toString(),
        "FalconNotYetSupported",
        `Expected FalconNotYetSupported, got: ${err}`,
      );
    }
  });

  // ── PQ Verifier Interface (additive) ──────────────────────────────────────
  //
  // Tests for the swappable verification backend:
  //   init_pq_verifier_config / verify_pq_signature / set_mode
  //
  // These are additive — the legacy verify_signature instruction and all
  // seven tests above remain untouched.

  describe("PQ Verifier Interface (additive)", () => {
    // Two governance authorities:
    //   multisigAuth — localnet config (cluster_is_mainnet = false)
    //   mainnetAuth  — mainnet config  (cluster_is_mainnet = true)
    const multisigAuth = Keypair.generate();
    const mainnetAuth  = Keypair.generate();
    const rogueUser    = Keypair.generate();

    let configPda: PublicKey;        // localnet config PDA
    let mainnetConfigPda: PublicKey; // mainnet config PDA (for StubForbiddenOnMainnet tests)

    const PQ_SCHEME_MLDSA44 = { mlDsa44:   {} };
    const MODE_STUB          = { stub:          {} };
    const MODE_SYSCALL       = { syscall:       {} };

    before("fund authorities, init localnet and mainnet PqVerifierConfig PDAs", async () => {
      // Fund all three keypairs
      for (const kp of [multisigAuth, mainnetAuth, rogueUser]) {
        const s = await connection.requestAirdrop(kp.publicKey, 5_000_000_000);
        await connection.confirmTransaction(s, "confirmed");
      }

      [configPda] = PublicKey.findProgramAddressSync(
        [Buffer.from("pq-verifier-config"), multisigAuth.publicKey.toBuffer()],
        FALCON_VERIFY_ID,
      );
      [mainnetConfigPda] = PublicKey.findProgramAddressSync(
        [Buffer.from("pq-verifier-config"), mainnetAuth.publicKey.toBuffer()],
        FALCON_VERIFY_ID,
      );

      // localnet config: cluster_is_mainnet = false, scheme = MlDsa44
      await falconVerify.methods
        .initPqVerifierConfig(false, PQ_SCHEME_MLDSA44)
        .accounts({
          config:        configPda,
          authority:     multisigAuth.publicKey,
          systemProgram: SystemProgram.programId,
          ...auditAccounts(),
        })
        .signers([multisigAuth])
        .rpc();

      // mainnet config: cluster_is_mainnet = true, scheme = MlDsa44
      await falconVerify.methods
        .initPqVerifierConfig(true, PQ_SCHEME_MLDSA44)
        .accounts({
          config:        mainnetConfigPda,
          authority:     mainnetAuth.publicKey,
          systemProgram: SystemProgram.programId,
          ...auditAccounts(),
        })
        .signers([mainnetAuth])
        .rpc();
    });

    // ── 8. init_pq_verifier_config ──────────────────────────────────────────

    it("8. init_pq_verifier_config stores authority, scheme, mode=Stub, and mainnet flag", async () => {
      const config = await falconVerify.account.pqVerifierConfig.fetch(configPda);
      assert.ok(config.authority.equals(multisigAuth.publicKey), "authority mismatch");
      assert.equal(config.clusterIsMainnet, false, "clusterIsMainnet should be false");
      assert.deepEqual(config.defaultScheme, PQ_SCHEME_MLDSA44, "default scheme mismatch");
      assert.deepEqual(config.mode, MODE_STUB, "initial mode should be Stub");

      const mainnetConfig = await falconVerify.account.pqVerifierConfig.fetch(mainnetConfigPda);
      assert.equal(mainnetConfig.clusterIsMainnet, true, "mainnet config flag wrong");
    });

    // ── 9. verify_pq_signature — Stub dispatches and accepts correct lengths ──

    it("9. verify_pq_signature dispatches to Stub backend and accepts correct-length sig/pk", async () => {
      const msg = Buffer.from("zynt-protocol-test-message");
      await falconVerify.methods
        .verifyPqSignature(PQ_SCHEME_MLDSA44, msg)
        .accounts({
          config:    configPda,
          signer:    multisigAuth.publicKey,
          sigBuffer: sigBufPda,
          pkBuffer:  pkBufPda,
        })
        .signers([multisigAuth])
        .rpc();
    });

    // ── 10. StubForbiddenOnMainnet guard in verify_pq_signature ───────────────

    it("10. verify_pq_signature Stub backend rejects on mainnet config (StubForbiddenOnMainnet)", async () => {
      const msg = Buffer.from("zynt-protocol-test-message");
      try {
        await falconVerify.methods
          .verifyPqSignature(PQ_SCHEME_MLDSA44, msg)
          .accounts({
            config:    mainnetConfigPda,
            signer:    mainnetAuth.publicKey,
            sigBuffer: sigBufPda,
            pkBuffer:  pkBufPda,
          })
          .signers([mainnetAuth])
          .rpc();
        assert.fail("Expected StubForbiddenOnMainnet");
      } catch (err: any) {
        assert.include(
          err.toString(),
          "StubForbiddenOnMainnet",
          `Expected StubForbiddenOnMainnet, got: ${err}`,
        );
      }
    });

    // ── 11. set_mode — non-authority rejected ─────────────────────────────────

    it("11. set_mode rejected when caller is not the config authority", async () => {
      try {
        // rogueUser passes itself as authority; Anchor re-derives the PDA from
        // rogue's key → seed mismatch → ConstraintSeeds before has_one is checked.
        await falconVerify.methods
          .setMode(MODE_SYSCALL)
          .accounts({
            config:    configPda,
            authority: rogueUser.publicKey,
            ...auditAccounts(),
          })
          .signers([rogueUser])
          .rpc();
        assert.fail("Expected authorization error");
      } catch (err: any) {
        assert.ok(
          err.toString().includes("UnauthorizedModeChange") ||
          err.toString().includes("ConstraintHasOne") ||
          err.toString().includes("ConstraintSeeds") ||
          err.toString().includes("2003") ||
          err.toString().includes("2006"),
          `Expected authorization error, got: ${err}`,
        );
      }
    });

    // ── 12. set_mode — authorized mode change + audit leaf ────────────────────

    it("12. set_mode changes mode to Syscall and appends audit leaf", async () => {
      const leafCountBefore = await getLeafCount();

      await falconVerify.methods
        .setMode(MODE_SYSCALL)
        .accounts({
          config:    configPda,
          authority: multisigAuth.publicKey,
          ...auditAccounts(),
        })
        .signers([multisigAuth])
        .rpc();

      const config = await falconVerify.account.pqVerifierConfig.fetch(configPda);
      assert.deepEqual(config.mode, MODE_SYSCALL, "mode should now be Syscall");

      const leafCountAfter = await getLeafCount();
      assert.equal(leafCountAfter, leafCountBefore + 1, "audit leaf not appended by set_mode");
    });

    // ── 13. verify_pq_signature — Syscall mode returns SyscallUnavailable ─────

    it("13. verify_pq_signature in Syscall mode returns SyscallUnavailable", async () => {
      const msg = Buffer.from("zynt-protocol-test-message");
      try {
        await falconVerify.methods
          .verifyPqSignature(PQ_SCHEME_MLDSA44, msg)
          .accounts({
            config:    configPda,
            signer:    multisigAuth.publicKey,
            sigBuffer: sigBufPda,
            pkBuffer:  pkBufPda,
          })
          .signers([multisigAuth])
          .rpc();
        assert.fail("Expected SyscallUnavailable");
      } catch (err: any) {
        assert.include(
          err.toString(),
          "SyscallUnavailable",
          `Expected SyscallUnavailable, got: ${err}`,
        );
      }
    });

    // ── 14. set_mode rejects Stub when cluster_is_mainnet ─────────────────────

    it("14. set_mode rejects setting Stub mode when cluster_is_mainnet is true (StubForbiddenOnMainnet)", async () => {
      // mainnet config currently has mode=Stub but the guard fires in set_mode too
      try {
        await falconVerify.methods
          .setMode(MODE_STUB)
          .accounts({
            config:    mainnetConfigPda,
            authority: mainnetAuth.publicKey,
            ...auditAccounts(),
          })
          .signers([mainnetAuth])
          .rpc();
        assert.fail("Expected StubForbiddenOnMainnet");
      } catch (err: any) {
        assert.include(
          err.toString(),
          "StubForbiddenOnMainnet",
          `Expected StubForbiddenOnMainnet, got: ${err}`,
        );
      }
    });

    // ── 15. additive — existing verify_signature still works under Stub mode ───

    it("15. existing verify_signature and new verify_pq_signature both work in Stub mode (additive)", async () => {
      // Restore localnet config to Stub so this test is self-contained
      await falconVerify.methods
        .setMode(MODE_STUB)
        .accounts({
          config:    configPda,
          authority: multisigAuth.publicKey,
          ...auditAccounts(),
        })
        .signers([multisigAuth])
        .rpc();

      const msg = Buffer.from("zynt-protocol-test-message");

      // Legacy instruction (called by hybrid_vault CPI) — must be unchanged
      await falconVerify.methods
        .verifySignature(SIG_TYPE_DILITHIUM3, msg)
        .accounts({
          signer:    testAuthority.publicKey,
          sigBuffer: sigBufPda,
          pkBuffer:  pkBufPda,
        })
        .signers([testAuthority])
        .rpc();

      // New stable entry point — Stub mode, same PqBuffers
      await falconVerify.methods
        .verifyPqSignature(PQ_SCHEME_MLDSA44, msg)
        .accounts({
          config:    configPda,
          signer:    multisigAuth.publicKey,
          sigBuffer: sigBufPda,
          pkBuffer:  pkBufPda,
        })
        .signers([multisigAuth])
        .rpc();
    });
  });
});
